Javascript.logic:
var opt = Services.getValue(NewAddressForService.dataBinding);

Services.setValue( NewAddL5.dataBinding, "");

if( 'ACK' == opt && null != solNode )
{	
	var ad5N = solNode.selectSingleNode("./ContactDetails/Address/Line[5]")
	if( 'ACK' == opt && null != ad5N)
	{ Services.setValue(NewAddL5.dataBinding, XML.getNodeTextContent(ad5N ));}
}
else if( 'ADDR' == opt && null != defNode )
{	Services.setValue(NewAddL5.dataBinding, XML.getNodeTextContent( defNode.selectSingleNode("./ContactDetails/Address/Line[5]")));
}
